class User_Model_User extends User_Model_Base_User {

    const TYPE_SUPERADMIN = 'superadmin';
    const TYPE_ADMIN = 'admin';
    const TYPE_API_USER = 'api-user';
    const TYPE_CUSTOMER = 'customer';

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        if($this->ID === null) {
            $this->Active = true;
            $this->DateTimeCreated = date('Y-m-d H:i:s');
            $this->RegistrationDate = date('Y-m-d');
        }
        $this->DateTimeUpdated = date('Y-m-d H:i:s');
        parent::save($conn);

    }

    /**
     * Get user by Email
     *
     * @param string|null $email
     * @param int|null $userID
     * @return array
     */
    public static function getUserByEmail(?string $email = null, int $userID = null): array {

        $query = Doctrine_Query::create();
        $query->from("User_Model_User object");
        $query->where("object.Name = ?", $email);

        if ( $userID )
            $query->addWhere("object.ID != ?", $userID);

        return $query->execute()->toArray();
    }

    /**
     * Get user by Email
     *
     * @param string|null $email
     * @return array
     */
    public static function getUserByEmailForLogin(?string $email = null): self|bool {
        $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from("User_Model_User object");
        $query->where("object.Name = ?", $email);
        $query->andWhere('object.Active = ?', true);

        if ( $eshop )
            $query->addWhere("object.Eshop_ID = ?", $eshop->ID);

        return $query->fetchOne();
    }

    /**
     * @return string
     */
    public static function generateSalt(): string {
        return substr( str_pad( dechex( mt_rand() ), 8, '0', STR_PAD_LEFT ), -8);
    }

    /**
     * @param string $password
     * @return string
     */
    public static function buildHash(string $password): string {
        return password_hash($password, PASSWORD_BCRYPT);
    }

    /**
     * @param string $email
     * @param string $password
     * @param string $type
     * @param Address|null $invoiceAddress
     * @param Address|null $deliveryAddress
     * @param int|null $eshopID
     * @return self
     */
    public static function createUser(string $email, string $password, string $type, int $eshopID = null, string $externalID = null, array $options=[]): self {
        $userSettings = new User_Model_UserSettings();
        $userSettings->save();

        $user = new User_Model_User();
        $user->UserSettings_ID = $userSettings->ID;
        $user->Name = $email;
        $user->Salt = self::generateSalt();
        $user->Hash = self::buildHash($password);
        $user->Type = $type;
        $user->RegistrationDate = date("Y-m-d");
        if ($externalID)
            $user->ExternalID = $externalID;
        if ( $eshopID )
            $user->Eshop_ID = $eshopID;
        $user->save();
        
        return $user;
    }

    /**
     * @param array $user
     * @param string $password
     * @param string $salt
     */
    public static function changePassword(array $user, string $password, string $salt) {
        $query = Doctrine_Query::create();
        $query->update('User_Model_User');
        $query->set('Salt', '?', $salt);
        $query->set('Hash', '?', self::buildHash($password));
        $query->where("ID = ?", $user[0]["ID"]);
        $query->execute();
    }

    /**
     * @return User_Model_User|null
     */
    public static function getCurrentUser() : ?User_Model_User {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User object');
        $query->where('object.ID = ?', UserClientSession::getCurrentUserID());

        $user = $query->fetchOne();

        return $user ?: null;
    }

    /**
     * Get user by value (Name, ID, ...)
     *
     * @param mixed $value
     * @param string $column
     * @return bool|self
     */
    public static function getUser(mixed $value, string $column = 'ID'): bool|self {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User object');
        $query->where('object.' . $column . ' = ?', $value);

        return $query->fetchOne();
    }

    /**
     * Get all types
     *
     * @param bool $showAll
     * @return string[]
     */
    public static function getUserTypes(bool $showAll = false): array {
        $types = [];
        $types[self::TYPE_SUPERADMIN] = 'Super administrátor';
        $types[self::TYPE_ADMIN] = 'Administrátor';
        $types[self::TYPE_API_USER] = 'Api uživatel';

        return array_merge($types,[
            self::TYPE_CUSTOMER => 'zákazník',
        ]);
    }

    /**
     * Get admin types
     *
     * @param bool $onlyKeys
     * @return string[]
     */
    public static function getAdminTypes(bool $onlyKeys = false): array {
        $types = [
            self::TYPE_SUPERADMIN => 'superadmin',
            self::TYPE_ADMIN => 'admin',
        ];

        return $onlyKeys?array_keys($types):$types;
    }

    /**
     * Get admin types
     *
     * @param bool $onlyKeys
     * @return string[]
     */
    public static function getApiUserTypes(bool $onlyKeys = false): array {
        $types = [
