    }

    /**
     * @param string|null $userType
     * @return int
     */
    public static function getUsersCount(?string $userType = null): int {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User object');
        $query->andWhere('object.Active = ?', true);
        if ( $userType )
            $query->andWhere('object.Type = ?', $userType);

        return $query->count();
    }

    /**
     * @param null $searchTerm
     * @param null $limit
     * @return array
     */
    public static function getSearchUsers($searchTerm = null, $limit = null): array {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User object');
        $query->leftJoin('object.invoiceAddress invoiceAddress');
        $query->orWhere('invoiceAddress.FirstName LIKE ?', '%' . $searchTerm . '%');
        $query->orWhere('invoiceAddress.LastName LIKE ?', '%' . $searchTerm . '%');
        $query->orWhere('invoiceAddress.CompanyName LIKE ?', '%' . $searchTerm . '%');
        $query->orWhere('object.Name LIKE ?', '%' . $searchTerm . '%');

        if ( $limit != null )
            $query->limit($limit);

        return $query->execute()->toArray();
    }

    /**
     * @param string $searchTerm
     * @return int
     */
    public static function getSearchUsersCount(string $searchTerm): int {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User object');
        $query->leftJoin('object.invoiceAddress invoiceAddress');
        $query->orWhere('invoiceAddress.FirstName LIKE ?', '%' . $searchTerm . '%');
        $query->orWhere('invoiceAddress.LastName LIKE ?', '%' . $searchTerm . '%');
        $query->orWhere('invoiceAddress.CompanyName LIKE ?', '%' . $searchTerm . '%');
        $query->orWhere('object.Name LIKE ?', '%' . $searchTerm . '%');

        return $query->count();
    }

    /**
     * @param string $userName
     * @return array|bool
     */
    public static function getUserForAdminLogin(string $userName): array|bool {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User user');
        $query->where('user.Name = ?', $userName);
        $query->addWhere('user.Active = ?', true);
        $query->addWhere('user.Type IN ("' . implode('","', self::getAdminTypes()) . '")');
        $query->having('COUNT(user.userEshops.ID) OR user.Type = ?', self::TYPE_SUPERADMIN);

        return $query->fetchOne([], Doctrine_Core::HYDRATE_ARRAY);
    }


    /**
     * @param string $userName
     * @return array|bool
     */
    public static function getUserForApiLogin(string $userName): self|bool {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User user');
        $query->where('user.Name = ?', $userName);
        $query->addWhere('user.Active = ?', true);
        $query->addWhere('user.Type IN ("' . implode('","', self::getApiUserTypes()) . '")');
        $query->having('COUNT(user.userEshops.ID) OR user.Type = ?', self::TYPE_API_USER);

        return $query->fetchOne();
    }

    public static function getAllUserEmails(int $EshopID): array {
        $query = Doctrine_Query::create();
        $query->from('User_Model_User user');
        $query->leftJoin('user.invoiceAddress invoiceAddress');
        $query->addWhere('user.Active = ?', true);
        $query->addWhere('user.Eshop_ID = ?', $EshopID);
        $query->addGroupBy('user.ID');
        $customerData = $query->execute([], Doctrine_Core::HYDRATE_ARRAY);
        $result = [];
        $index = 0;

        foreach ($customerData as &$data) {
            $result[$index] = $data['invoiceAddress']['Email'] ?? '';
            $index++;
        }
        return $result;
    }

    /**
     * Has permission?
     *
     * @param string $Code
     * @return bool
     */
    public function hasPermission(string $Code): bool {
        $perms = $this->userHasPermissions;
        $permission = PermissionModel::getPermissionByCode($Code, true);

        if ($this->Type === self::TYPE_SUPERADMIN)
            return true;

        foreach ($perms as $perm) {
            if ($perm->Permission_ID == $permission->ID)
                return true;
        }

        return false;
    }

    /**
     * @param int $userID
     * @param string $code
     * @return bool
     */
    public static function userHasPermission(int $userID, string $code): bool {
        $user = self::getUser($userID);
        if (!$user)
            return false;

        return $user->hasPermission($code);
    }

