        /**
         * @throws Doctrine_Query_Exception
         * @throws Exception
         */
        public static function confirmUserRegistration(string $token): self | bool
        {
            try {
                $parsedTokenData = Tokenizer::parseToken($token);
                $user = self::getUser($parsedTokenData['ID']);
                if (!$user || $user->Name !== $parsedTokenData['Name']) {
                    throw new Exception('Invalid token data');
                }
                $user->Active = true;
                $user->save();
                return $user;
            } catch (Exception $e) {
                throw new Exception($e->getMessage());
            }
        }


    /**
     * @return bool
     */
    public function isSuperadmin(): bool {
        return $this->Type === self::TYPE_SUPERADMIN;
    }
